// Only continue for newly opened issues - GitHub's webhook also fires for edited/closed/labeled etc.
// Handles both the real GitHub Trigger shape (flat) and a generic Webhook node's shape (nested under .body),
// since the generic Webhook node is the easiest way to test this without GitHub credentials.
const raw = $input.first().json;
const payload = raw.body || raw;
const action = payload.action;
const issue = payload.issue || {};

if (action !== 'opened') {
  return [];
}

return [{
  json: {
    issueNumber: issue.number,
    title: issue.title || '(no title)',
    bodyText: issue.body || '(no description provided)',
    author: issue.user?.login || 'unknown',
    url: issue.html_url,
    owner: payload.repository?.owner?.login,
    repo: payload.repository?.name
  }
}];

// Build a short text block of other currently-open issues for Claude to compare the new issue against,
// excluding the new issue itself (in case of any list/webhook timing overlap).
const prior = $('Filter Opened Issues').first().json;
const candidates = $input.all()
  .map((item) => item.json)
  .filter((i) => typeof i.number === 'number' && i.number !== prior.issueNumber);

const candidateBlock = candidates.length === 0
  ? 'No other open issues to compare against.'
  : candidates.map((i) => `#${i.number}: ${i.title}\n${(i.body || '(no description)').slice(0, 300)}`).join('\n\n');

return [{ json: { ...prior, candidateBlock } }];

// Claude is instructed to return raw JSON, but strip code fences defensively in case it doesn't comply
const response = $input.first().json;
const raw = response.content?.[0]?.text || '{}';
const cleaned = raw.trim().replace(/^```(json)?/i, '').replace(/```$/, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { labels: [], needsRepro: false, comment: '', duplicateOf: null, mergeSummary: '' };
}

const prior = $('Filter Opened Issues').first().json;

return [{
  json: {
    ...prior,
    labels: Array.isArray(parsed.labels) ? parsed.labels : [],
    needsRepro: !!parsed.needsRepro,
    comment: parsed.comment || '',
    duplicateOf: (typeof parsed.duplicateOf === 'number') ? parsed.duplicateOf : null,
    mergeSummary: parsed.mergeSummary || ''
  }
}];

// Append (or update) a tracked summary block at the bottom of the ORIGINAL issue's body,
// so the running count and merged details survive even if this workflow runs many times.
// A hidden HTML-comment marker stores the structured data; everything between
// DUPLICATE_TRACKER_START/END is regenerated fresh on every run rather than stacking duplicate blocks.
const original = $input.first().json;
const newDetail = $('Extract Data from Claude JSON').first().json.mergeSummary;
const reporter = $('Extract Data from Claude JSON').first().json.author;
const newIssueNumber = $('Extract Data from Claude JSON').first().json.issueNumber;

const body = original.body || '';
const startMarker = '<!-- DUPLICATE_TRACKER_START -->';
const endMarker = '<!-- DUPLICATE_TRACKER_END -->';
const blockRegex = new RegExp(`${startMarker}[\\s\\S]*?${endMarker}`);
const dataRegex = /<!-- DUPLICATE_TRACKER_DATA: ([\s\S]*?) -->/;

let details = [];
const dataMatch = body.match(dataRegex);
if (dataMatch) {
  try {
    details = JSON.parse(dataMatch[1]).details || [];
  } catch (e) {
    details = [];
  }
}

if (newDetail) {
  details.push(`#${newIssueNumber} (@${reporter}): ${newDetail}`);
}

const count = details.length + 1; // +1 for the original reporter
const detailLines = details.length > 0 ? details.map((d) => `- ${d}`).join('\n') : '- (no additional details yet)';
const newBlock = `${startMarker}\n---\n**\ud83d\udd01 Reported by ${count} user(s) so far.** Additional details collected from other reports:\n${detailLines}\n<!-- DUPLICATE_TRACKER_DATA: ${JSON.stringify({ details })} -->\n${endMarker}`;

const newBody = blockRegex.test(body) ? body.replace(blockRegex, newBlock) : `${body}\n\n${newBlock}`;

return [{
  json: {
    owner: original.owner?.login || $('Extract Data from Claude JSON').first().json.owner,
    repo: original.repository?.name || $('Extract Data from Claude JSON').first().json.repo,
    originalIssueNumber: original.number,
    newBody,
    mergeSummary: newDetail,
    newIssueNumber,
    reporter
  }
}];
